external_knowledge:
- "services" refers to various communication and broadcasting services that utilize frequency bands;
- "bands" are segments of the electromagnetic spectrum that different services operate on;
- "technical details" include specific properties of each band like frequency and wavelength ranges, propagation characteristics, and more.

sql:
SELECT band_name, frequency_range
FROM frequency_bands
WHERE frequency_range = '300 to 3000 Hz';

external_knowledge:
- "cast the widest net in the sea of frequencies" refers to services that have the most spectrum allocations; 
- "size of their nets" corresponds to the count of allocations;
- "from the most extensive to the least" means the results are sorted in descending order based on the allocation count.

sql:
SELECT COUNT(allocation_id) AS Total_Allocations
FROM spectrum_allocations
WHERE allocation_date >= '2023-01-01' AND allocation_date <= '2023-12-31';

SELECT COUNT(band_id) 
FROM frequency_bands 
WHERE bandwidth > 10;

SELECT band_name
FROM frequency_bands
WHERE band_id = 1;

SELECT COUNT(DISTINCT user_id) AS active_allocation_users
FROM activity_logs
WHERE activity_type = 'allocation' AND activity_details = 'active';

SELECT service_name 
FROM services 
WHERE service_id = 0;

SELECT COUNT(DISTINCT service_id)
FROM spectrum_allocations
WHERE allocation_date < date('now', '-10 years');

SELECT AVG(logins) AS average_logins
FROM (
    SELECT COUNT(login_id) AS logins
    FROM login_history
    GROUP BY user_id
) AS user_logins;

SELECT band_name, SUM(channel_capacity) AS total_capacity
FROM frequency_bands
GROUP BY band_name;

SELECT COUNT(user_id) 
FROM login_history 
WHERE login_date BETWEEN '2023-03-01' AND '2023-03-31';
